#include<bits/stdc++.h>
using namespace std;
int n,m,len,a[50010],k,cnt1[50010],cnt2[50010];
long long sum,ans[50010];
struct query
{
    int l,r,id,k;
    bool operator<(const query&b)const
    {
        if(l/len!=b.l/len)
        {
            return l<b.l;
        }
        return (((l/len)&1)?r<b.r:r>b.r);
    }
}q[200010];
void addl(int x)
{
    sum+=cnt1[a[x]];
    cnt2[a[x]]++;
}
void addr(int x)
{
    sum+=cnt2[a[x]];
    cnt1[a[x]]++;
}
void dell(int x)
{
    sum-=cnt1[a[x]];
    cnt2[a[x]]--;
}
void delr(int x)
{
    sum-=cnt2[a[x]];
    cnt1[a[x]]--;
}
int tot;
void push(int x,int y,int id,int k)
{
    q[++tot].id=id;
    q[tot].l=x;
    q[tot].r=y;
    q[tot].k=k;
}
int main()
{
    scanf("%d",&n);
    len=sqrt(n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    scanf("%d",&m);
    for(int i=1;i<=m;i++)
    {
        int l1,r1,l2,r2;
        scanf("%d%d%d%d",&l1,&r1,&l2,&r2);
        push(r1,r2,i,-1);
        push(l2-1,r1,i,1);
        push(l1-1,r2,i,1);
        push(l1-1,l2-1,i,-1);
    }
    sort(q+1,q+1+tot);
    int l=0,r=0;
    for(int i=1;i<=tot;i++)
    {
        while(l<q[i].l)
        {
            dell(++l);
        }
        while(l>q[i].l)
        {
            addl(l--);
        }
        while(r<q[i].r)
        {
            addr(++r);
        }
        while(r>q[i].r)
        {
            delr(r--);
        }
        ans[q[i].id]+=q[i].k*sum;
    }
    for(int i=1;i<=m;i++)
    {
        printf("%lld\n",ans[i]);
    }
    return 0;
}
